// nodes/transformNode.js
import { BaseNode } from './BaseNode';
import { Wrench } from 'lucide-react';

export const TransformNode = ({ id, data, selected }) => {
  return (
    <BaseNode
      id={id}
      title="Transform"
      icon={Wrench}
      accentColor="var(--accent-violet)"
      inputs={[{ id: 'input', label: 'input' }]}
      outputs={[{ id: 'output', label: 'output' }]}
      selected={selected}
    >
      <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '8px' }}>
          <div style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--accent-violet)' }} />
          <span style={{ fontWeight: 500, color: 'var(--text-primary)' }}>{data?.language || 'javascript'}</span>
        </div>
        <div style={{ fontSize: '11px', color: 'var(--text-tertiary)', background: 'var(--bg-app)', padding: '6px 8px', borderRadius: '4px', border: '1px solid var(--border-subtle)', fontFamily: 'monospace', maxHeight: '40px', overflow: 'hidden', textOverflow: 'ellipsis' }}>
          {data?.code || '// transform(input)'}
        </div>
      </div>
    </BaseNode>
  );
};
